lines = []
# SupplierTab
lines.append('')
lines.append('// ─── SUPPLIER TAB (MP-10) ────────────────────────────────────────────────────')
lines.append('function SupplierTab({ suppliers, setSuppliers }) {')
lines.append('  const [modal, setModal] = useState(null);')
lines.append('  const [form, setForm] = useState({});')
lines.append('  const enriched = suppliers.map(s => {')
lines.append('    const nextEvalDate = addDays(s.lastEvalDate, s.evalIntervalDays);')
lines.append('    const days = daysUntil(nextEvalDate);')
lines.append('    return { ...s, nextEvalDate, days };')
lines.append('  }).sort((a,b) => a.days-b.days);')
lines.append('  function handleUpdate() {')
lines.append('    setSuppliers(prev => prev.map(s => s.id===modal.id ? { ...s, lastEvalDate: form.date, evalScore: parseInt(form.score), evalResult: parseInt(form.score)>=90?"\u512a\u826f":parseInt(form.score)>=80?"\u5408\u683c":parseInt(form.score)>=70?"\u689d\u4ef6\u5408\u683c":"\u4e0d\u5408\u683c" } : s));')
lines.append('    setModal(null);')
lines.append('  }')
lines.append('  const scoreColor = s => s>=90?"#22c55e":s>=80?"#60a5fa":s>=70?"#eab308":"#ef4444";')
lines.append('  return (')
lines.append('    <div>')
lines.append('      <SectionHeader title="\u4f9b\u61c9\u5546\u8a55\u9451\u7ba1\u7406\uff08MP-10\uff09" count={suppliers.length} color="#06b6d4" />')
lines.append('      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap" }}>')
lines.append('        <StatCard label="\u4f9b\u61c9\u5546\u7e3d\u6578" value={suppliers.length} color="#06b6d4" />')
lines.append('        <StatCard label="\u512a\u826f" value={enriched.filter(s=>s.evalResult==="\u512a\u826f").length} color="#22c55e" />')
lines.append('        <StatCard label="\u689d\u4ef6\u5408\u683c" value={enriched.filter(s=>s.evalResult==="\u689d\u4ef6\u5408\u683c").length} color="#eab308" />')
lines.append('        <StatCard label="\u8a55\u9451\u903e\u671f" value={enriched.filter(s=>s.days<0).length} color="#ef4444" />')
lines.append('      </div>')
lines.append('      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>')
lines.append('        {enriched.map(s => (')
lines.append('          <div key={s.id} style={{ background: urgencyBg(s.days), border: `1px solid ${urgencyColor(s.days)}33`, borderRadius: 12, padding: "16px 18px" }}>')
lines.append('            <div style={{ display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap", marginBottom: s.issues.length>0?10:0 }}>')
lines.append('              <div style={{ flex: 1, minWidth: 200 }}>')
lines.append('                <div style={{ fontWeight: 700, color: "#e2e8f0", fontSize: 14 }}>{s.name}</div>')
lines.append('                <div style={{ fontSize: 12, color: "#64748b", marginTop: 2 }}>{s.id} \u00b7 {s.category} \u00b7 \u806f\u7d61\u4eba\uff1a{s.contact}</div>')
lines.append('              </div>')
lines.append('              <div style={{ textAlign: "right", minWidth: 90 }}>')
lines.append('                <div style={{ fontSize: 24, fontWeight: 800, color: scoreColor(s.evalScore), fontFamily: "monospace" }}>{s.evalScore}</div>')
lines.append('                <div style={{ fontSize: 11, color: "#64748b" }}>\u5206</div>')
lines.append('              </div>')
lines.append('              <Badge color={s.evalResult==="\u512a\u826f"?"#22c55e":s.evalResult==="\u5408\u683c"?"#60a5fa":s.evalResult==="\u689d\u4ef6\u5408\u683c"?"#eab308":"#ef4444"}>{s.evalResult}</Badge>')
lines.append('              <div style={{ textAlign: "right", minWidth: 120 }}>')
lines.append('                <div style={{ fontSize: 12, color: "#64748b" }}>\u4e0b\u6b21\u8a55\u9451</div>')
lines.append('                <div style={{ fontWeight: 700, color: "#e2e8f0", fontSize: 13 }}>{formatDate(s.nextEvalDate)}</div>')
lines.append('              </div>')
lines.append('              <Badge color={urgencyColor(s.days)}>{urgencyLabel(s.days)}</Badge>')
lines.append('              <button onClick={() => { setModal(s); setForm({ date: new Date().toISOString().split("T")[0], score: s.evalScore }); }} style={{ background: "rgba(255,255,255,0.08)", border: "1px solid rgba(255,255,255,0.15)", borderRadius: 8, color: "#94a3b8", cursor: "pointer", padding: "6px 14px", fontSize: 12 }}>\u66f4\u65b0\u8a55\u9451</button>')
lines.append('            </div>')
lines.append('            {s.issues.length>0 && (')
lines.append('              <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>')
lines.append('                <span style={{ fontSize: 11, color: "#ef4444", fontWeight: 600 }}>\u554f\u984c\u9805\u76ee\uff1a</span>')
lines.append('                {s.issues.map((issue,i) => (<span key={i} style={{ fontSize: 11, background: "rgba(239,68,68,0.1)", color: "#f87171", borderRadius: 6, padding: "2px 8px", border: "1px solid rgba(239,68,68,0.2)" }}>{issue}</span>))}')
lines.append('              </div>')
lines.append('            )}')
lines.append('          </div>')
lines.append('        ))}')
lines.append('      </div>')
lines.append('      {modal && (<Modal title={`\u66f4\u65b0\u8a55\u9451\uff1a${modal.name}`} onClose={() => setModal(null)}><div style={{ display: "flex", flexDirection: "column", gap: 16 }}><div><div style={{ fontSize: 12, color: "#64748b", marginBottom: 6 }}>\u8a55\u9451\u65e5\u671f</div><input type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})} style={inputStyle} /></div><div><div style={{ fontSize: 12, color: "#64748b", marginBottom: 6 }}>\u8a55\u9451\u7e3d\u5206 (0-100)</div><input type="number" min="0" max="100" value={form.score} onChange={e=>setForm({...form,score:e.target.value})} style={inputStyle} /></div><div style={{ background: "rgba(6,182,212,0.1)", borderRadius: 8, padding: 12 }}><div style={{ fontSize: 12, color: "#22d3ee", fontWeight: 600 }}>\u8a55\u5b9a\u7b49\u7d1a\uff1a{parseInt(form.score)>=90?"\u512a\u826f":parseInt(form.score)>=80?"\u5408\u683c":parseInt(form.score)>=70?"\u689d\u4ef6\u5408\u683c":"\u4e0d\u5408\u683c"}</div><div style={{ fontSize: 11, color: "#64748b", marginTop: 4 }}>90+\u512a\u826f / 80-89\u5408\u683c / 70-79\u689d\u4ef6\u5408\u683c / 69\u4ee5\u4e0b\u4e0d\u5408\u683c</div></div><button onClick={handleUpdate} style={{ background: "linear-gradient(135deg, #0891b2, #06b6d4)", border: "none", borderRadius: 10, color: "#fff", cursor: "pointer", padding: "12px 24px", fontSize: 15, fontWeight: 700 }}>\u2713 \u78ba\u8a8d\u66f4\u65b0\u8a55\u9451</button></div></Modal>)}')
lines.append('    </div>')
lines.append('  );')
lines.append('}')
lines.append('')
# NonConformanceTab
lines.append('// ─── NON-CONFORMANCE TAB (MP-15) ─────────────────────────────────────────────')
lines.append('function NonConformanceTab({ ncs, setNcs }) {')
lines.append('  const [modal, setModal] = useState(null);')
lines.append('  const [showAdd, setShowAdd] = useState(false);')
lines.append('  const [newNc, setNewNc] = useState({ id:"", date:"", dept:"", type:"\u88fd\u7a0b\u7570\u5e38", description:"", severity:"\u8f15\u5fae", rootCause:"", correctiveAction:"", responsible:"", dueDate:"", status:"\u5f85\u8655\u7406", closeDate:"", effectiveness:"" });')
lines.append('  const statusColor = s => s==="\u5df2\u95dc\u9589"?"#22c55e":s==="\u8655\u7406\u4e2d"?"#f97316":s==="\u5f85\u8655\u7406"?"#ef4444":"#eab308";')
lines.append('  const sevColor = s => s==="\u91cd\u5927"?"#ef4444":s==="\u8f15\u5fae"?"#eab308":"#60a5fa";')
lines.append('  const enriched = ncs.map(nc => ({...nc, overdue: nc.status!=="\u5df2\u95dc\u9589" && daysUntil(nc.dueDate)<0 }));')
lines.append('  function addNc() {')
lines.append('    const id = "NC-" + new Date().getFullYear() + "-" + String(ncs.length+1).padStart(3,"0");')
lines.append('    setNcs(prev => [...prev, { ...newNc, id }]);')
lines.append('    setShowAdd(false);')
lines.append('    setNewNc({ id:"", date:"", dept:"", type:"\u88fd\u7a0b\u7570\u5e38", description:"", severity:"\u8f15\u5fae", rootCause:"", correctiveAction:"", responsible:"", dueDate:"", status:"\u5f85\u8655\u7406", closeDate:"", effectiveness:"" });')
lines.append('  }')
lines.append('  function closeNc(nc) {')
lines.append('    setNcs(prev => prev.map(n => n.id===nc.id ? {...n, status:"\u5df2\u95dc\u9589", closeDate:new Date().toISOString().split("T")[0], effectiveness:"\u6709\u6548"} : n));')
lines.append('    setModal(null);')
lines.append('  }')
lines.append('  return (')
lines.append('    <div>')
lines.append('      <SectionHeader title="\u4e0d\u7b26\u5408\u53ca\u77ef\u6b63\u63aa\u65bd\uff08MP-15\uff09" count={ncs.length} color="#f87171" />')
lines.append('      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap" }}>')
lines.append('        <StatCard label="\u5f85\u8655\u7406" value={ncs.filter(n=>n.status==="\u5f85\u8655\u7406").length} color="#ef4444" sub="\u9700\u7acb\u5373\u8655\u7406" />')
lines.append('        <StatCard label="\u8655\u7406\u4e2d" value={ncs.filter(n=>n.status==="\u8655\u7406\u4e2d").length} color="#f97316" sub="\u8ffd\u8e64\u4e2d" />')
lines.append('        <StatCard label="\u5df2\u95dc\u9589" value={ncs.filter(n=>n.status==="\u5df2\u95dc\u9589").length} color="#22c55e" sub="\u5df2\u5b8c\u6210" />')
lines.append('        <StatCard label="\u903e\u671f\u672a\u7d50\u6848" value={enriched.filter(n=>n.overdue).length} color="#ef4444" sub="\u903e\u671f\u8655\u7406" />')
lines.append('      </div>')
lines.append('      <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 14 }}>')
lines.append('        <button onClick={() => setShowAdd(true)} style={{ background: "linear-gradient(135deg, #dc2626, #ef4444)", border: "none", borderRadius: 10, color: "#fff", cursor: "pointer", padding: "9px 18px", fontSize: 13, fontWeight: 700 }}>\uff0b \u65b0\u589e\u4e0d\u7b26\u5408\u5831\u544a</button>')
lines.append('      </div>')
lines.append('      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>')
lines.append('        {enriched.map(nc => (')
lines.append('          <div key={nc.id} style={{ background: nc.overdue?"rgba(239,68,68,0.12)":"rgba(255,255,255,0.03)", border: `1px solid ${nc.overdue?"rgba(239,68,68,0.3)":"rgba(255,255,255,0.08)"}`, borderRadius: 12, padding: "14px 18px" }}>')
lines.append('            <div style={{ display: "flex", alignItems: "flex-start", gap: 12, flexWrap: "wrap" }}>')
lines.append('              <div style={{ flex: 1, minWidth: 260 }}>')
lines.append('                <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 6, flexWrap: "wrap" }}>')
lines.append('                  <span style={{ fontWeight: 700, color: "#60a5fa", fontFamily: "monospace", fontSize: 13 }}>{nc.id}</span>')
lines.append('                  <Badge color={sevColor(nc.severity)}>{nc.severity}</Badge>')
lines.append('                  <Badge color={statusColor(nc.status)}>{nc.status}</Badge>')
lines.append('                  {nc.overdue && <Badge color="#ef4444">\u903e\u671f\u672a\u7d50\u6848</Badge>}')
lines.append('                </div>')
lines.append('                <div style={{ color: "#e2e8f0", fontWeight: 600, fontSize: 14, marginBottom: 4 }}>{nc.description}</div>')
lines.append('                <div style={{ fontSize: 12, color: "#64748b" }}>{nc.dept} \u00b7 {nc.type} \u00b7 \u767c\u73fe\uff1a{formatDate(nc.date)} \u00b7 \u8acb\u516c\uff1a{nc.responsible}</div>')
lines.append('              </div>')
lines.append('              <div style={{ textAlign: "right", minWidth: 120 }}>')
lines.append('                <div style={{ fontSize: 12, color: "#64748b" }}>\u5230\u671f\u65e5\u671f</div>')
lines.append('                <div style={{ fontWeight: 700, color: nc.overdue?"#ef4444":"#e2e8f0", fontSize: 13 }}>{formatDate(nc.dueDate)}</div>')
lines.append('                {nc.status==="\u5df2\u95dc\u9589" && <div style={{ fontSize: 11, color: "#4ade80", marginTop: 4 }}>\u95dc\u9589\uff1a{formatDate(nc.closeDate)}</div>}')
lines.append('              </div>')
lines.append('              <button onClick={() => setModal(nc)} style={{ background: "rgba(255,255,255,0.08)", border: "1px solid rgba(255,255,255,0.15)", borderRadius: 8, color: "#94a3b8", cursor: "pointer", padding: "6px 14px", fontSize: 12 }}>\u8a73\u60c5</button>')
lines.append('            </div>')
lines.append('          </div>')
lines.append('        ))}')
lines.append('      </div>')
lines.append('      {modal && (<Modal title={`\u4e0d\u7b26\u5408\u8a73\u60c5\uff1a${modal.id}`} onClose={() => setModal(null)}><div style={{ display: "flex", flexDirection: "column", gap: 14 }}>{[["\u767c\u73fe\u65e5\u671f",formatDate(modal.date)],["\u767c\u73fe\u90e8\u9580",modal.dept],["\u4e0d\u7b26\u5408\u985e\u578b",modal.type],["\u56b4\u91cd\u5ea6",modal.severity],["\u554f\u984c\u63cf\u8ff0",modal.description],["\u6839\u672c\u539f\u56e0",modal.rootCause],["\u77ef\u6b63\u63aa\u65bd",modal.correctiveAction],["\u8cc7\u4efb\u4eba",modal.responsible],["\u5230\u671f\u65e5\u671f",formatDate(modal.dueDate)],["\u72c0\u614b",modal.status],["\u95dc\u9589\u65e5\u671f",formatDate(modal.closeDate)],["\u6709\u6548\u6027\u9a57\u8b49",modal.effectiveness||"\u5c1a\u672a\u9a57\u8b49"]].map(([k,v]) => (<div key={k} style={{ display:"flex", gap:12 }}><div style={{ fontSize:12, color:"#64748b", minWidth:90 }}>{k}</div><div style={{ color:"#e2e8f0", fontWeight:600, fontSize:13 }}>{v}</div></div>))}{modal.status!=="\u5df2\u95dc\u9589" && (<button onClick={() => closeNc(modal)} style={{ background:"linear-gradient(135deg,#059669,#10b981)", border:"none", borderRadius:10, color:"#fff", cursor:"pointer", padding:"12px 24px", fontSize:14, fontWeight:700, marginTop:8 }}>\u2713 \u6a19\u8a18\u70ba\u5df2\u95dc\u9589</button>)}</div></Modal>)}')
lines.append('      {showAdd && (<Modal title="\u65b0\u589e\u4e0d\u7b26\u5408\u5831\u544a" onClose={() => setShowAdd(false)}><div style={{ display:"flex", flexDirection:"column", gap:12 }}>{[["\u767c\u73fe\u65e5\u671f","date","date"],["\u767c\u73fe\u90e8\u9580","dept","text"],["\u554f\u984c\u63cf\u8ff0","description","text"],["\u6839\u672c\u539f\u56e0","rootCause","text"],["\u77ef\u6b63\u63aa\u65bd","correctiveAction","text"],["\u8cc7\u4efb\u4eba","responsible","text"],["\u5230\u671f\u65e5\u671f","dueDate","date"]].map(([label,field,type]) => (<div key={field}><div style={{ fontSize:12, color:"#64748b", marginBottom:5 }}>{label}</div><input type={type} value={newNc[field]} onChange={e=>setNewNc({...newNc,[field]:e.target.value})} style={inputStyle} /></div>))}<div><div style={{ fontSize:12, color:"#64748b", marginBottom:5 }}>\u4e0d\u7b26\u5408\u985e\u578b</div><select value={newNc.type} onChange={e=>setNewNc({...newNc,type:e.target.value})} style={inputStyle}><option>\u88fd\u7a0b\u7570\u5e38</option><option>\u91cf\u6e2c\u7570\u5e38</option><option>\u4f86\u6599\u4e0d\u5408\u683c</option><option>\u6587\u4ef6\u4e0d\u7b26</option><option>\u5ba2\u6236\u6295\u8a34</option></select></div><div><div style={{ fontSize:12, color:"#64748b", marginBottom:5 }}>\u56b4\u91cd\u5ea6</div><select value={newNc.severity} onChange={e=>setNewNc({...newNc,severity:e.target.value})} style={inputStyle}><option>\u8f15\u5fae</option><option>\u91cd\u5927</option></select></div><button onClick={addNc} style={{ background:"linear-gradient(135deg,#dc2626,#ef4444)", border:"none", borderRadius:10, color:"#fff", cursor:"pointer", padding:"12px 24px", fontSize:15, fontWeight:700, marginTop:8 }}>\uff0b \u65b0\u589e\u4e0d\u7b26\u5408\u5831\u544a</button></div></Modal>)}')
lines.append('    </div>')
lines.append('  );')
lines.append('}')

content = '\n'.join(lines) + '\n'
with open(r'C:\Users\USER\Desktop\自動稽核程式\audit-dashboard.jsx', 'a', encoding='utf-8-sig') as f:
    f.write(content)
print('Part5 SupplierTab+NonConformanceTab OK')
